"""NIP-01 event model — the trust root of the platform.

Canonical id computation, signing, and verification for Nostr events.
Every other Lindenmayer component consumes events through this module;
nothing here knows about Lindenmayer kinds, relays, or Buzz.

Canonical serialization follows NIP-01: the id is the SHA-256 of the
UTF-8 JSON array ``[0, pubkey, created_at, kind, tags, content]`` with no
whitespace. Python's ``json.dumps(ensure_ascii=False, separators=(",", ":"))``
produces the same escaping as ``JSON.stringify`` (the de-facto reference
via nostr-tools), which is what published event ids are computed with.
"""

from __future__ import annotations

import hashlib
import json
import time
from dataclasses import dataclass, field
from typing import Any, Iterator

import lindenmayer.core.keys as _keys

__all__ = ["Event", "EventValidationError", "canonical_serialization", "compute_event_id"]


class EventValidationError(ValueError):
    """Raised when an event fails structural validation."""


def canonical_serialization(
    pubkey: str, created_at: int, kind: int, tags: list[list[str]], content: str
) -> bytes:
    """The NIP-01 canonical byte serialization whose SHA-256 is the event id."""
    return json.dumps(
        [0, pubkey, created_at, kind, tags, content],
        ensure_ascii=False,
        separators=(",", ":"),
    ).encode("utf-8")


def compute_event_id(
    pubkey: str, created_at: int, kind: int, tags: list[list[str]], content: str
) -> str:
    """Lowercase hex SHA-256 of the canonical serialization."""
    return hashlib.sha256(
        canonical_serialization(pubkey, created_at, kind, tags, content)
    ).hexdigest()


def _is_hex(value: str, length: int) -> bool:
    if len(value) != length or value != value.lower():
        return False
    try:
        bytes.fromhex(value)
    except ValueError:
        return False
    return True


@dataclass(frozen=True, slots=True)
class Event:
    """An immutable NIP-01 event.

    ``tags`` is stored as a tuple of tuples so instances are hashable; the
    wire form (``to_dict``/``to_json``) uses lists per NIP-01.
    """

    pubkey: str
    created_at: int
    kind: int
    tags: tuple[tuple[str, ...], ...]
    content: str
    id: str
    sig: str | None = field(default=None)

    # -- construction ------------------------------------------------------

    @classmethod
    def build(
        cls,
        *,
        pubkey: str,
        kind: int,
        tags: list[list[str]] | tuple[tuple[str, ...], ...] = (),
        content: str = "",
        created_at: int | None = None,
    ) -> "Event":
        """Build an unsigned event with a freshly computed id."""
        ts = int(time.time()) if created_at is None else int(created_at)
        tag_lists = [list(t) for t in tags]
        event_id = compute_event_id(pubkey, ts, kind, tag_lists, content)
        return cls(
            pubkey=pubkey,
            created_at=ts,
            kind=kind,
            tags=tuple(tuple(t) for t in tags),
            content=content,
            id=event_id,
        )

    @classmethod
    def from_dict(cls, data: dict[str, Any]) -> "Event":
        """Parse a wire-format event dict, validating structure (not signature)."""
        try:
            pubkey = data["pubkey"]
            created_at = data["created_at"]
            kind = data["kind"]
            tags = data["tags"]
            content = data["content"]
            event_id = data["id"]
        except (KeyError, TypeError) as exc:
            raise EventValidationError(f"missing event field: {exc}") from exc
        sig = data.get("sig")
        if not isinstance(pubkey, str) or not _is_hex(pubkey, 64):
            raise EventValidationError("pubkey must be 64-char lowercase hex")
        if not isinstance(event_id, str) or not _is_hex(event_id, 64):
            raise EventValidationError("id must be 64-char lowercase hex")
        if sig is not None and (not isinstance(sig, str) or not _is_hex(sig, 128)):
            raise EventValidationError("sig must be 128-char lowercase hex")
        if not isinstance(created_at, int) or isinstance(created_at, bool):
            raise EventValidationError("created_at must be an integer")
        if not isinstance(kind, int) or isinstance(kind, bool) or not 0 <= kind <= 65535:
            raise EventValidationError("kind must be an integer in [0, 65535]")
        if not isinstance(content, str):
            raise EventValidationError("content must be a string")
        if not isinstance(tags, list) or any(
            not isinstance(t, list) or any(not isinstance(v, str) for v in t) for t in tags
        ):
            raise EventValidationError("tags must be a list of lists of strings")
        return cls(
            pubkey=pubkey,
            created_at=created_at,
            kind=kind,
            tags=tuple(tuple(t) for t in tags),
            content=content,
            id=event_id,
            sig=sig,
        )

    @classmethod
    def from_json(cls, raw: str | bytes) -> "Event":
        try:
            data = json.loads(raw)
        except json.JSONDecodeError as exc:
            raise EventValidationError(f"invalid JSON: {exc}") from exc
        if not isinstance(data, dict):
            raise EventValidationError("event JSON must be an object")
        return cls.from_dict(data)

    # -- serialization -----------------------------------------------------

    def to_dict(self) -> dict[str, Any]:
        data: dict[str, Any] = {
            "id": self.id,
            "pubkey": self.pubkey,
            "created_at": self.created_at,
            "kind": self.kind,
            "tags": [list(t) for t in self.tags],
            "content": self.content,
        }
        if self.sig is not None:
            data["sig"] = self.sig
        return data

    def to_json(self) -> str:
        return json.dumps(self.to_dict(), ensure_ascii=False, separators=(",", ":"))

    # -- integrity ---------------------------------------------------------

    def recompute_id(self) -> str:
        return compute_event_id(
            self.pubkey, self.created_at, self.kind, [list(t) for t in self.tags], self.content
        )

    def id_valid(self) -> bool:
        """Does the declared id match the canonical serialization?"""
        return self.id == self.recompute_id()

    def sig_valid(self) -> bool:
        """Is the signature a valid BIP-340 signature by ``pubkey`` over ``id``?

        False when unsigned. Does not check the id itself — use ``verify``.
        """
        if self.sig is None:
            return False
        return _keys.schnorr_verify(self.pubkey, bytes.fromhex(self.id), bytes.fromhex(self.sig))

    def verify(self) -> bool:
        """Full NIP-01 verification: id matches content AND signature is valid.

        This is the platform's trust root — every consumer that reads from a
        relay must call this (or a helper that does) before believing an event.
        """
        return self.id_valid() and self.sig_valid()

    # -- tag access --------------------------------------------------------

    def tag_values(self, name: str) -> Iterator[tuple[str, ...]]:
        """Yield the value portions (everything after the name) of matching tags."""
        for tag in self.tags:
            if tag and tag[0] == name:
                yield tag[1:]

    def first_tag_value(self, name: str) -> str | None:
        """The first value of the first tag named ``name``, or None."""
        for values in self.tag_values(name):
            return values[0] if values else None
        return None

"""secp256k1 key handling: BIP-340 Schnorr signing and verification.

Thin wrapper over coincurve (libsecp256k1 — the BIP-340 reference C
implementation). This module is the only place in Lindenmayer that touches
raw key material; everything else works with hex pubkeys and `Event`s.

Key-material discipline: secrets live in memory as bytes, are never logged,
and never appear in repr/str output.
"""

from __future__ import annotations

from coincurve.keys import PrivateKey, PublicKeyXOnly

__all__ = ["Keypair", "schnorr_sign", "schnorr_verify"]


def schnorr_verify(pubkey_hex: str, message: bytes, signature: bytes) -> bool:
    """Verify a BIP-340 Schnorr signature by an x-only pubkey over ``message``.

    Returns False (never raises) on malformed keys or signatures — callers
    treat verification failure uniformly regardless of why the input is bad.
    """
    try:
        pubkey = PublicKeyXOnly(bytes.fromhex(pubkey_hex))
        return pubkey.verify(signature, message)
    except Exception:
        return False


def schnorr_sign(secret: bytes, message: bytes, aux_rand: bytes | None = None) -> bytes:
    """Produce a BIP-340 Schnorr signature over ``message``.

    ``aux_rand`` is the 32-byte auxiliary randomness from BIP-340; None lets
    the backend choose (test vectors pass it explicitly).
    """
    key = PrivateKey(secret)
    if aux_rand is None:
        return key.sign_schnorr(message)
    return key.sign_schnorr(message, aux_randomness=aux_rand)


class Keypair:
    """A secp256k1 keypair identified by its x-only public key (hex)."""

    __slots__ = ("_private",)

    def __init__(self, secret: bytes) -> None:
        if len(secret) != 32:
            raise ValueError("secret key must be exactly 32 bytes")
        self._private = PrivateKey(secret)

    @classmethod
    def generate(cls) -> "Keypair":
        return cls(PrivateKey().secret)

    @classmethod
    def from_hex(cls, secret_hex: str) -> "Keypair":
        return cls(bytes.fromhex(secret_hex))

    @property
    def public_key_hex(self) -> str:
        """The 64-char lowercase hex x-only public key (the Nostr pubkey)."""
        return self._private.public_key_xonly.format().hex()

    def sign(self, message: bytes, aux_rand: bytes | None = None) -> bytes:
        if aux_rand is None:
            return self._private.sign_schnorr(message)
        return self._private.sign_schnorr(message, aux_randomness=aux_rand)

    def sign_event(self, event):  # noqa: ANN001, ANN201 — Event typed at call sites; avoids import cycle
        """Return a signed copy of ``event`` authored by this keypair.

        The event's pubkey must already be this keypair's pubkey (the id
        commits to the pubkey, so signing someone else's event body would
        just produce an invalid event).
        """
        from dataclasses import replace

        if event.pubkey != self.public_key_hex:
            raise ValueError("event.pubkey does not match this keypair")
        if not event.id_valid():
            raise ValueError("event id does not match its canonical serialization")
        signature = self.sign(bytes.fromhex(event.id))
        return replace(event, sig=signature.hex())

    def __repr__(self) -> str:  # never leak the secret
        return f"Keypair(pubkey={self.public_key_hex})"

"""Deployment configuration: relay URL, key material, capability attestations.

No new storage systems (DESIGN.md §6.2): configuration is a TOML file read
with stdlib ``tomllib`` plus environment variables. Key material is never
stored in the config file itself — the file names *where* the key lives
(an env var or a file path), and ``load_keypair`` resolves it at runtime.

Capability attestations are the "verify, don't infer" mechanism from the
relay-integration research: relay-side behaviors that degrade silently on a
plain NIP-29 relay (private-group read gating above all) must be explicitly
attested by the deployment operator before the library will rely on them.
Absence of an attestation is a hard "no", not a "probably".
"""

from __future__ import annotations

import os
import tomllib
from pathlib import Path

from pydantic import BaseModel, Field, field_validator

from lindenmayer.core.keys import Keypair

__all__ = [
    "CAP_PRIVATE_READ_GATING",
    "CapabilityAttestation",
    "ConfigError",
    "CoreConfig",
]

# The one degradation that is not cosmetic (research aggregate, finding 4):
# relay-side enforcement of NIP-29 `private` read gating. Buzz satisfies it
# by construction; "NIP-29 compliant" alone does not.
CAP_PRIVATE_READ_GATING = "nip29-private-read-gating"


class ConfigError(ValueError):
    """Raised when configuration is missing, malformed, or unresolvable."""


class CapabilityAttestation(BaseModel):
    """An operator's explicit statement that this deployment's relay enforces
    a capability that the protocol alone does not guarantee.

    This is a config-level record of an operational fact, attributable to
    whoever operates the deployment — not a signed wire event. Consumers
    that need wire-level proof verify from the signed log (verify module).
    """

    capability: str
    attested_by: str = Field(description="operator identity: name or pubkey hex")
    attested_at: int = Field(description="unix timestamp of the attestation")
    note: str = ""

    @field_validator("capability", "attested_by")
    @classmethod
    def _non_empty(cls, value: str) -> str:
        if not value.strip():
            raise ValueError("must be non-empty")
        return value


class CoreConfig(BaseModel):
    """Top-level configuration for a Lindenmayer deployment."""

    relay_url: str
    capability_attestations: list[CapabilityAttestation] = Field(default_factory=list)
    secret_key_env: str = "LINDENMAYER_SECRET_KEY"
    secret_key_file: Path | None = None

    @field_validator("relay_url")
    @classmethod
    def _ws_url(cls, value: str) -> str:
        if not value.startswith(("ws://", "wss://")):
            raise ValueError("relay_url must be a ws:// or wss:// URL")
        return value

    # -- capabilities ------------------------------------------------------

    def has_capability(self, capability: str) -> bool:
        """True only if the deployment explicitly attests ``capability``."""
        return any(a.capability == capability for a in self.capability_attestations)

    def attestation_for(self, capability: str) -> CapabilityAttestation | None:
        for attestation in self.capability_attestations:
            if attestation.capability == capability:
                return attestation
        return None

    # -- key material ------------------------------------------------------

    def load_keypair(self) -> Keypair:
        """Resolve key material: env var first, then key file.

        The secret is 64-char hex. It never transits the config file; a
        world-readable key file is refused outright.
        """
        secret_hex = os.environ.get(self.secret_key_env, "").strip()
        if secret_hex:
            return self._keypair_from_hex(secret_hex, source=f"${self.secret_key_env}")
        if self.secret_key_file is not None:
            path = self.secret_key_file.expanduser()
            if not path.is_file():
                raise ConfigError(f"secret key file not found: {path}")
            mode = path.stat().st_mode & 0o777
            if mode & 0o077:
                raise ConfigError(
                    f"secret key file {path} is group/world-accessible "
                    f"(mode {mode:o}); chmod 600 it"
                )
            return self._keypair_from_hex(path.read_text().strip(), source=str(path))
        raise ConfigError(
            f"no key material: ${self.secret_key_env} is unset and no "
            "secret_key_file is configured"
        )

    @staticmethod
    def _keypair_from_hex(secret_hex: str, *, source: str) -> Keypair:
        try:
            return Keypair.from_hex(secret_hex)
        except ValueError as exc:
            # Deliberately excludes the material itself from the message.
            raise ConfigError(f"invalid secret key from {source}: {exc}") from exc

    # -- loading -----------------------------------------------------------

    @classmethod
    def from_toml(cls, path: str | Path) -> "CoreConfig":
        path = Path(path)
        try:
            data = tomllib.loads(path.read_text())
        except (OSError, tomllib.TOMLDecodeError) as exc:
            raise ConfigError(f"cannot read config {path}: {exc}") from exc
        try:
            return cls.model_validate(data)
        except ValueError as exc:
            raise ConfigError(f"invalid config {path}: {exc}") from exc
